const body = $json.body || $json || {};
const normalizedJobIds = Array.isArray(body.job_ids)
  ? body.job_ids.map((value) => String(value || '').trim()).filter(Boolean)
  : [];
const limit = Math.max(1, Math.min(20, Number(body.limit || 10) || 10));
const automationId = String(body.automation_id || 'phase6-follow-up-reminder').trim() || 'phase6-follow-up-reminder';
const channel = String(body.channel || 'n8n').trim().toLowerCase() || 'n8n';
const deliveryMode = String(body.delivery_mode || 'telegram').trim().toLowerCase() || 'telegram';
const defaultChatId = String(body.test_chat_id || '8724583836').trim() || '8724583836';
return [{
  json: {
    job_ids: normalizedJobIds,
    due_only: body.due_only === undefined ? true : !!body.due_only,
    limit,
    dry_run: body.dry_run === undefined ? false : !!body.dry_run,
    channel,
    automation_id: automationId,
    delivery_mode: deliveryMode,
    force_failure: !!body.force_failure,
    test_chat_id: defaultChatId,
    requested_by: $execution.mode || 'unknown'
  }
}];

const run = $json || {};
return [{
  json: {
    run_id: run.run_id || null,
    workflow: 'workflow_06d_follow_up_reminders',
    queued: Number(run.queued || 0),
    skipped: Number(run.skipped || 0),
    dry_run: !!run.dry_run,
    items: Array.isArray(run.items) ? run.items : [],
    message: run.message || 'No reminder items were queued.'
  }
}];

const run = $json || {};
const inputItems = $items('Prepare Reminder Run Input', 0, 0);
const input = Array.isArray(inputItems) && inputItems.length ? inputItems[0].json : {};
const items = Array.isArray(run.items) ? run.items : [];
return items.map((item) => ({
  json: {
    run_id: run.run_id || null,
    job_id: item.job_id,
    message: item.message,
    channel: item.channel || input.channel || 'n8n',
    automation_id: item.automation_id || input.automation_id || 'phase6-follow-up-reminder',
    force_failure: !!input.force_failure,
    test_chat_id: input.test_chat_id || '8724583836',
    delivery_mode: input.delivery_mode || 'telegram'
  }
}));

const baseItems = $items('Split Reminder Items', 0, $itemIndex);
const base = Array.isArray(baseItems) && baseItems.length ? { ...baseItems[0].json } : {};
const sendResult = $json || {};
const failed = !!(sendResult.error || sendResult.ok === false);
const errorMessage = failed
  ? String(sendResult.description || sendResult.message || sendResult.error?.message || 'telegram_send_failed')
  : null;
const now = new Date().toISOString();
return [{
  json: {
    ...base,
    writeback_status: failed ? 'failed' : 'sent',
    delivery_failed: failed,
    delivery_error: errorMessage,
    last_run_at: now,
    delivered_at: failed ? null : now,
    notes: failed
      ? `Reminder delivery failed in n8n: ${errorMessage}`
      : 'Reminder delivered by n8n workflow.'
  }
}];

const item = $json || {};
return [{
  json: {
    workflow: 'workflow_06d_follow_up_reminders',
    run_id: item.run_id || null,
    job_id: item.jobId || item.job_id || null,
    reminder_status: (((item.workflow || {}).followUp || {}).reminder || {}).status || null,
    last_run_at: ((((item.workflow || {}).followUp || {}).reminder || {}).lastRunAt) || null,
    delivered_at: ((((item.workflow || {}).followUp || {}).reminder || {}).deliveredAt) || null,
    notes: ((((item.workflow || {}).followUp || {}).reminder || {}).notes) || null,
    title: item.title || null,
    company: item.company || null
  }
}];
